from flask import Blueprint, jsonify, request, g
from auth import login_required
from services.notification_service import NotificationService

bp = Blueprint("notifications", __name__, url_prefix="/api/notifications")
svc = NotificationService()


@bp.route("", methods=["GET"])
@login_required
def list_notifications():
    """GET /api/notifications?unread=true&limit=20&offset=0"""
    unread = request.args.get("unread", "false").lower() == "true"
    limit = min(int(request.args.get("limit", 20)), 100)
    offset = int(request.args.get("offset", 0))

    items = svc.get_notifications(
        g.user_id, limit=limit, offset=offset, unread_only=unread,
    )
    return jsonify({"notifications": items, "offset": offset, "limit": limit})


@bp.route("/count", methods=["GET"])
@login_required
def unread_count():
    """GET /api/notifications/count"""
    count = svc.get_unread_count(g.user_id)
    return jsonify({"unread_count": count})


@bp.route("/<int:nid>/read", methods=["PUT"])
@login_required
def mark_read(nid: int):
    """PUT /api/notifications/<id>/read"""
    ok = svc.mark_read(nid, g.user_id)
    if not ok:
        return jsonify({"error": "Not found"}), 404
    return jsonify({"success": True})


@bp.route("/read-all", methods=["PUT"])
@login_required
def mark_all_read():
    """PUT /api/notifications/read-all"""
    count = svc.mark_all_read(g.user_id)
    return jsonify({"marked": count})


@bp.route("/<int:nid>", methods=["DELETE"])
@login_required
def delete_notification(nid: int):
    """DELETE /api/notifications/<id>"""
    ok = svc.delete_notification(nid, g.user_id)
    if not ok:
        return jsonify({"error": "Not found"}), 404
    return jsonify({"success": True})


@bp.route("/preferences", methods=["GET"])
@login_required
def get_preferences():
    """GET /api/notifications/preferences"""
