import { useState, useEffect, useCallback } from 'react';
import {
  Container, Typography, ToggleButtonGroup, ToggleButton,
  Box, Button, Select, MenuItem, FormControl, InputLabel,
  CircularProgress,
} from '@mui/material';
import DoneAllIcon from '@mui/icons-material/DoneAll';
import { NotificationItem } from '../components/NotificationItem';
import { useNotifications } from '../hooks/useNotifications';

type Filter = 'all' | 'unread' | 'read';

export default function NotificationPage() {
  const [filter, setFilter] = useState<Filter>('all');
  const [typeFilter, setTypeFilter] = useState<string>('all');
  const {
    notifications, loading, hasMore,
    markRead, markAllRead, deleteNotification, loadMore, refresh,
  } = useNotifications();

  useEffect(() => { refresh(); }, [refresh]);

  const handleScroll = useCallback(() => {
    if (loading || !hasMore) return;
    const { scrollTop, scrollHeight, clientHeight } = document.documentElement;
    if (scrollHeight - scrollTop - clientHeight < 200) loadMore();
  }, [loading, hasMore, loadMore]);

  useEffect(() => {
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, [handleScroll]);

  const filtered = notifications.filter((n) => {
    if (filter === 'unread' && n.is_read) return false;
    if (filter === 'read' && !n.is_read) return false;
    if (typeFilter !== 'all' && n.type !== typeFilter) return false;
    return true;
  });

  const notifTypes = [...new Set(notifications.map((n) => n.type))];

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 3 }}>
        <Typography variant="h4">Notifications</Typography>
        <Button startIcon={<DoneAllIcon />} onClick={() => markAllRead()}>Mark all read</Button>
      </Box>

      <Box sx={{ display: 'flex', gap: 2, mb: 3, flexWrap: 'wrap' }}>
        <ToggleButtonGroup value={filter} exclusive onChange={(_, v) => v && setFilter(v)} size="small">
          <ToggleButton value="all">All</ToggleButton>
          <ToggleButton value="unread">Unread</ToggleButton>
          <ToggleButton value="read">Read</ToggleButton>
        </ToggleButtonGroup>

        <FormControl size="small" sx={{ minWidth: 160 }}>
          <InputLabel>Type</InputLabel>
          <Select value={typeFilter} label="Type" onChange={(e) => setTypeFilter(e.target.value)}>
            <MenuItem value="all">All types</MenuItem>
            {notifTypes.map((t) => (
              <MenuItem key={t} value={t}>{t.replace(/_/g, ' ')}</MenuItem>
            ))}
          </Select>
        </FormControl>
      </Box>

      {filtered.length === 0 && !loading ? (
        <Typography color="text.secondary" sx={{ textAlign: 'center', py: 8 }}>
          No notifications to show.
        </Typography>
      ) : (
        filtered.map((n) => (
          <NotificationItem
            key={n.id}
            notification={n}
            onClick={() => markRead(n.id)}
            onDelete={() => deleteNotification(n.id)}
          />
        ))
      )}

      {loading && (
        <Box sx={{ textAlign: 'center', py: 3 }}><CircularProgress size={28} /></Box>
      )}
    </Container>
  );
}

import { useState, useEffect, useCallback, useRef } from 'react';
import { io, Socket } from 'socket.io-client';

interface Notification {
  id: number;
  type: string;
  title: string;
  body: string;
  icon: string;
  action_url?: string;
  actor_avatar?: string;
  actor_username?: string;
  is_read: boolean;
  created_at: string;
}

const API = '/api/notifications';
const notificationSound = new Audio('/sounds/notification.mp3');

export function useNotifications() {
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [hasMore, setHasMore] = useState(true);
  const offsetRef = useRef(0);
  const socketRef = useRef<Socket | null>(null);

  const refresh = useCallback(async () => {
    setLoading(true);
    const [listRes, countRes] = await Promise.all([
      fetch(`${API}?limit=20&offset=0`),
      fetch(`${API}/count`),
    ]);
    const listData = await listRes.json();
    const countData = await countRes.json();
    setNotifications(listData.notifications);
    setUnreadCount(countData.unread_count);
    offsetRef.current = listData.notifications.length;
    setHasMore(listData.notifications.length === 20);
    setLoading(false);
  }, []);

  const loadMore = useCallback(async () => {
    if (loading) return;
    setLoading(true);
    const res = await fetch(`${API}?limit=20&offset=${offsetRef.current}`);
    const data = await res.json();
    setNotifications((prev) => [...prev, ...data.notifications]);
    offsetRef.current += data.notifications.length;
    setHasMore(data.notifications.length === 20);
    setLoading(false);
  }, [loading]);

  // WebSocket connection for real-time updates
  useEffect(() => {
    const token = localStorage.getItem('token') ?? '';
    const socket = io(window.location.origin, { query: { token } });
    socketRef.current = socket;

    socket.on('new_notification', (notif: Notification) => {
      setNotifications((prev) => [notif, ...prev]);
      setUnreadCount((c) => c + 1);
      notificationSound.play().catch(() => {});

      if (Notification.permission === 'granted') {
        new Notification(notif.title, {
          body: notif.body,
          icon: '/icon-192.png',
        });
      }
    });

    socket.on('unread_count', (data: { count: number }) => {
      setUnreadCount(data.count);
    });

    return () => { socket.disconnect(); };
  }, []);

  const markRead = useCallback(async (id: number) => {
    await fetch(`${API}/${id}/read`, { method: 'PUT' });
    setNotifications((prev) =>
      prev.map((n) => (n.id === id ? { ...n, is_read: true } : n)),
    );
    setUnreadCount((c) => Math.max(0, c - 1));
  }, []);

  const markAllRead = useCallback(async () => {
    await fetch(`${API}/read-all`, { method: 'PUT' });
    setNotifications((prev) => prev.map((n) => ({ ...n, is_read: true })));
    setUnreadCount(0);
  }, []);

  const deleteNotification = useCallback(async (id: number) => {
    await fetch(`${API}/${id}`, { method: 'DELETE' });
    setNotifications((prev) => {
      const target = prev.find((n) => n.id === id);
      if (target && !target.is_read) setUnreadCount((c) => Math.max(0, c - 1));
      return prev.filter((n) => n.id !== id);
    });
  }, []);

  return {
    notifications, unreadCount, loading, hasMore,
    markRead, markAllRead, deleteNotification, refresh, loadMore,
  };
}

import json
import queue
import threading
from flask import Blueprint, Response, g
from auth import login_required

bp = Blueprint("sse", __name__)

_user_queues: dict[int, list[queue.Queue]] = {}
_lock = threading.Lock()


def send_sse(user_id: int, event: str, data: dict):
    """Push an SSE event to all connected clients for a user."""
    with _lock:
        for q in _user_queues.get(user_id, []):
            q.put(f"event: {event}\ndata: {json.dumps(data)}\n\n")


@bp.route("/api/notifications/stream")
@login_required
def stream():
    user_id = g.user_id
    q: queue.Queue = queue.Queue()

    with _lock:
        _user_queues.setdefault(user_id, []).append(q)

    def generate():
        try:
            while True:
                msg = q.get()
                yield msg
        finally:
            with _lock:
                _user_queues[user_id].remove(q)

    return Response(
        generate(),
        mimetype="text/event-stream",
        headers={"Cache-Control": "no-cache", "X-Accel-Buffering": "no"},
    )

import { useState, useEffect, useRef } from 'react';

export function usePollingNotifications(intervalMs = 30_000) {
  const [unreadCount, setUnreadCount] = useState(0);
  const timerRef = useRef<ReturnType<typeof setInterval>>();

  useEffect(() => {
    async function poll() {
      try {
        const res = await fetch('/api/notifications/count');
        const data = await res.json();
        setUnreadCount(data.unread_count);
      } catch {
        // Silently retry on next interval
      }
    }

    poll();
    timerRef.current = setInterval(poll, intervalMs);
    return () => clearInterval(timerRef.current);
  }, [intervalMs]);

  return { unreadCount };
}

async function subscribeToPush() {
  const registration = await navigator.serviceWorker.register('/sw.js');

  const permission = await Notification.requestPermission();
  if (permission !== 'granted') return null;

  const subscription = await registration.pushManager.subscribe({
    userVisibleOnly: true,
    applicationServerKey: urlBase64ToUint8Array(VAPID_PUBLIC_KEY),
  });

  await fetch('/api/push/subscribe', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify(subscription.toJSON()),
  });

  return subscription;
}

function urlBase64ToUint8Array(base64String) {
  const padding = '='.repeat((4 - base64String.length % 4) % 4);
  const base64 = (base64String + padding)
    .replace(/-/g, '+').replace(/_/g, '/');
  const raw = window.atob(base64);
  return Uint8Array.from([...raw].map((c) => c.charCodeAt(0)));
}

self.addEventListener('push', (event) => {
  const data = event.data?.json() ?? {};

  event.waitUntil(
    self.registration.showNotification(data.title ?? 'New notification', {
      body: data.body ?? '',
      icon: data.icon ?? '/icon-192.png',
      badge: '/badge-72.png',
      data: { url: data.url ?? '/' },
      vibrate: [200, 100, 200],
      tag: data.tag ?? 'default',
    }),
  );
});

self.addEventListener('notificationclick', (event) => {
  event.notification.close();
  const targetUrl = event.notification.data?.url ?? '/';

  event.waitUntil(
    clients.matchAll({ type: 'window' }).then((windowClients) => {
      for (const client of windowClients) {
        if (client.url.includes(targetUrl) && 'focus' in client) {
          return client.focus();
        }
      }
      return clients.openWindow(targetUrl);
    }),
  );
});

import { useState, useEffect } from 'react';
import { Alert, Button, Collapse, Typography } from '@mui/material';
import NotificationsActiveIcon from '@mui/icons-material/NotificationsActive';

export function PushPermissionBanner() {
  const [show, setShow] = useState(false);

  useEffect(() => {
    if ('Notification' in window && Notification.permission === 'default') {
      const timer = setTimeout(() => setShow(true), 10_000);
      return () => clearTimeout(timer);
    }
  }, []);

  async function handleEnable() {
    const permission = await Notification.requestPermission();
    if (permission === 'granted') {
      await (window as any).subscribeToPush?.();
    }
    setShow(false);
  }

  return (
    <Collapse in={show}>
      <Alert
        severity="info"
        icon={<NotificationsActiveIcon />}
        action={
          <>
            <Button color="inherit" size="small" onClick={handleEnable}>Enable</Button>
            <Button color="inherit" size="small" onClick={() => setShow(false)}>Not now</Button>
          </>
        }
        sx={{ mb: 2 }}
      >
        <Typography variant="body2">
          Get notified about replies, mentions, and important updates even when you are not on the site.
        </Typography>
      </Alert>
    </Collapse>
  );
}

import { useState, useEffect } from 'react';
import {
  Container, Typography, Table, TableBody, TableCell,
  TableContainer, TableHead, TableRow, Switch, Paper,
  Button, Select, MenuItem, Box, Alert,
} from '@mui/material';
import VolumeOffIcon from '@mui/icons-material/VolumeOff';

interface Pref {
  notification_type: string;
  in_app: boolean;
  push: boolean;
  email: boolean;
}

const NOTIF_TYPES = [
  { key: 'new_follower', label: 'New followers' },
  { key: 'comment_reply', label: 'Comment replies' },
  { key: 'post_liked', label: 'Post likes' },
  { key: 'mention', label: 'Mentions' },
  { key: 'direct_message', label: 'Direct messages' },
  { key: 'achievement', label: 'Achievements' },
  { key: 'system', label: 'System announcements' },
];

export function NotificationPreferences() {
  const [prefs, setPrefs] = useState<Pref[]>([]);
  const [muteHours, setMuteHours] = useState<number>(0);
  const [saved, setSaved] = useState(false);

  useEffect(() => {
    fetch('/api/notifications/preferences')
      .then((r) => r.json())
      .then((data) => {
        const serverMap = new Map(
          data.preferences.map((p: any) => [p.notification_type, p]),
        );
        setPrefs(
          NOTIF_TYPES.map((t) => {
            const existing = serverMap.get(t.key) as any;
            return {
              notification_type: t.key,
              in_app: existing?.in_app_enabled ?? true,
              push: existing?.push_enabled ?? true,
              email: existing?.email_enabled ?? true,
            };
          }),
        );
      });
  }, []);

  function toggle(index: number, channel: 'in_app' | 'push' | 'email') {
    setPrefs((prev) =>
      prev.map((p, i) => (i === index ? { ...p, [channel]: !p[channel] } : p)),
    );
    setSaved(false);
  }

  async function save() {
    await fetch('/api/notifications/preferences', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ preferences: prefs }),
    });
    setSaved(true);
  }

  function muteAll() {
    if (muteHours <= 0) return;
    const until = Date.now() + muteHours * 60 * 60 * 1000;
    localStorage.setItem('notifications_muted_until', String(until));
  }

  return (
    <Container maxWidth="md" sx={{ py: 4 }}>
      <Typography variant="h5" gutterBottom>Notification Preferences</Typography>

      {saved && <Alert severity="success" sx={{ mb: 2 }}>Preferences saved successfully.</Alert>}

      <Box sx={{ display: 'flex', gap: 2, mb: 3, alignItems: 'center' }}>
        <VolumeOffIcon color="action" />
        <Typography>Mute all notifications for</Typography>
        <Select size="small" value={muteHours} onChange={(e) => setMuteHours(Number(e.target.value))}>
          <MenuItem value={0}>Select duration</MenuItem>
          <MenuItem value={1}>1 hour</MenuItem>
          <MenuItem value={4}>4 hours</MenuItem>
          <MenuItem value={8}>8 hours</MenuItem>
          <MenuItem value={24}>24 hours</MenuItem>
        </Select>
        <Button variant="outlined" size="small" disabled={muteHours === 0} onClick={muteAll}>Mute</Button>
      </Box>

      <TableContainer component={Paper} variant="outlined">
        <Table>
          <TableHead>
            <TableRow>
              <TableCell>Notification Type</TableCell>
              <TableCell align="center">In-App</TableCell>
              <TableCell align="center">Push</TableCell>
              <TableCell align="center">Email</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {prefs.map((pref, i) => (
              <TableRow key={pref.notification_type}>
                <TableCell>{NOTIF_TYPES.find((t) => t.key === pref.notification_type)?.label}</TableCell>
                <TableCell align="center"><Switch checked={pref.in_app} onChange={() => toggle(i, 'in_app')} /></TableCell>
                <TableCell align="center"><Switch checked={pref.push} onChange={() => toggle(i, 'push')} /></TableCell>
                <TableCell align="center"><Switch checked={pref.email} onChange={() => toggle(i, 'email')} /></TableCell>
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </TableContainer>

      <Box sx={{ mt: 3, textAlign: 'right' }}>
        <Button variant="contained" onClick={save}>Save preferences</Button>
      </Box>
    </Container>
  );
}

import {
  createContext, useContext, useState, useCallback, ReactNode,
} from 'react';
import { Snackbar, Alert, AlertColor, Slide } from '@mui/material';

interface Toast {
  id: number;
  message: string;
  severity: AlertColor;
  duration: number;
}

interface ToastContextValue {
  showToast: (message: string, severity?: AlertColor, duration?: number) => void;
}

const ToastContext = createContext<ToastContextValue>({ showToast: () => {} });

let nextId = 0;

export function ToastProvider({ children }: { children: ReactNode }) {
  const [toasts, setToasts] = useState<Toast[]>([]);

  const showToast = useCallback(
    (message: string, severity: AlertColor = 'info', duration = 4000) => {
      const id = nextId++;
      setToasts((prev) => [...prev, { id, message, severity, duration }]);
    },
    [],
  );

  const dismiss = useCallback((id: number) => {
    setToasts((prev) => prev.filter((t) => t.id !== id));
  }, []);

  return (
    <ToastContext.Provider value={{ showToast }}>
      {children}
      {toasts.map((toast, index) => (
        <Snackbar
          key={toast.id}
          open
          autoHideDuration={toast.duration}
          onClose={() => dismiss(toast.id)}
          anchorOrigin={{ vertical: 'bottom', horizontal: 'right' }}
          TransitionComponent={Slide}
          sx={{ bottom: { xs: 24 + index * 60 } }}
        >
          <Alert
            severity={toast.severity}
            variant="filled"
            onClose={() => dismiss(toast.id)}
            sx={{ width: '100%', minWidth: 300 }}
          >
            {toast.message}
          </Alert>
        </Snackbar>
      ))}
    </ToastContext.Provider>
  );
}

export const useToast = () => useContext(ToastContext);

